// ============================================================
// PKCE Utilities (Proof Key for Code Exchange)
// ============================================================
function generateRandomString(length) {
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => byte.toString(16).padStart(2, '0')).join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await crypto.subtle.digest('SHA-256', data);
  return base64UrlEncode(digest);
}

function base64UrlEncode(arrayBuffer) {
  const bytes = new Uint8Array(arrayBuffer);
  let binary = '';
  bytes.forEach((byte) => {
    binary += String.fromCharCode(byte);
  });
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function generateState() {
  return generateRandomString(32);
}

// ============================================================
// Token Storage Utilities
// ============================================================
const TOKEN_KEYS = {
  accessToken: 'oauth_access_token',
  refreshToken: 'oauth_refresh_token',
  tokenExpiry: 'oauth_token_expiry',
  idToken: 'oauth_id_token',
  codeVerifier: 'oauth_code_verifier',
  state: 'oauth_state',
};

function storeTokens(tokenResponse) {
  const expiryTime = Date.now() + tokenResponse.expires_in * 1000;
  localStorage.setItem(TOKEN_KEYS.accessToken, tokenResponse.access_token);
  localStorage.setItem(TOKEN_KEYS.tokenExpiry, expiryTime.toString());

  if (tokenResponse.refresh_token) {
    localStorage.setItem(TOKEN_KEYS.refreshToken, tokenResponse.refresh_token);
  }
  if (tokenResponse.id_token) {
    localStorage.setItem(TOKEN_KEYS.idToken, tokenResponse.id_token);
  }
}

function getStoredTokens() {
  return {
    accessToken: localStorage.getItem(TOKEN_KEYS.accessToken),
    refreshToken: localStorage.getItem(TOKEN_KEYS.refreshToken),
    tokenExpiry: localStorage.getItem(TOKEN_KEYS.tokenExpiry),
    idToken: localStorage.getItem(TOKEN_KEYS.idToken),
  };
}

function clearTokens() {
  Object.values(TOKEN_KEYS).forEach((key) => localStorage.removeItem(key));
}

function isTokenExpired() {
  const expiry = localStorage.getItem(TOKEN_KEYS.tokenExpiry);
  if (!expiry) return true;
  // Consider token expired 60 seconds before actual expiry
  return Date.now() > parseInt(expiry, 10) - 60000;
}

// ============================================================
// OAuth Service
// ============================================================
const OAuthService = {
  async initiateLogin() {
    const codeVerifier = generateRandomString(64);
    const codeChallenge = await generateCodeChallenge(codeVerifier);
    const state = generateState();

    // Store PKCE verifier and state for later verification
    localStorage.setItem(TOKEN_KEYS.codeVerifier, codeVerifier);
    localStorage.setItem(TOKEN_KEYS.state, state);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAUTH_CONFIG.clientId,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      scope: OAUTH_CONFIG.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
    window.location.href = authUrl;
  },

  async exchangeCodeForTokens(code, state) {
    // Verify state parameter to prevent CSRF
    const storedState = localStorage.getItem(TOKEN_KEYS.state);
    if (!storedState || storedState !== state) {
      throw new Error('Invalid state parameter. Possible CSRF attack.');
    }

    const codeVerifier = localStorage.getItem(TOKEN_KEYS.codeVerifier);
    if (!codeVerifier) {
      throw new Error('Missing PKCE code verifier. Authentication flow is invalid.');
    }

    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      code_verifier: codeVerifier,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        `Token exchange failed: ${errorData.error_description || errorData.error || response.statusText}`
      );
    }

    const tokenResponse = await response.json();

    // Clean up PKCE and state values
    localStorage.removeItem(TOKEN_KEYS.codeVerifier);
    localStorage.removeItem(TOKEN_KEYS.state);

    // Store tokens
    storeTokens(tokenResponse);

    return tokenResponse;
  },

  async refreshAccessToken() {
    const { refreshToken } = getStoredTokens();
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      clearTokens();
      throw new Error('Token refresh failed');
    }

    const tokenResponse = await response.json();
    storeTokens(tokenResponse);
    return tokenResponse;
  },

  async getValidAccessToken() {
    const { accessToken } = getStoredTokens();

    if (!accessToken) {
      throw new Error('No access token available');
    }

    if (isTokenExpired()) {
      try {
        const newTokens = await this.refreshAccessToken();
        return newTokens.access_token;
      } catch (error) {
        clearTokens();
        throw new Error('Session expired. Please log in again.');
      }
    }

    return accessToken;
  },

  logout() {
    const { idToken } = getStoredTokens();
    clearTokens();

    if (OAUTH_CONFIG.logoutEndpoint) {
      const params = new URLSearchParams({
        id_token_hint: idToken || '',
        post_logout_redirect_uri: window.location.origin,
      });
      window.location.href = `${OAUTH_CONFIG.logoutEndpoint}?${params.toString()}`;
    } else {
      window.location.href = '/';
    }
  },
};

// ============================================================
// Authenticated Fetch Wrapper
// ============================================================
async function authenticatedFetch(url, options = {}) {
  const accessToken = await OAuthService.getValidAccessToken();

  const headers = {
    ...options.headers,
    Authorization: `Bearer ${accessToken}`,
  };

  let response = await fetch(url, { ...options, headers });

  // If 401, try refreshing the token once
  if (response.status === 401) {
    try {
      const newTokens = await OAuthService.refreshAccessToken();
      headers.Authorization = `Bearer ${newTokens.access_token}`;
      response = await fetch(url, { ...options, headers });
    } catch (refreshError) {
      clearTokens();
      throw new Error('Session expired. Please log in again.');
    }
  }

  return response;
}

