const AuthContext = createContext(null);

function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);

  const fetchUserProfile = useCallback(async () => {
    try {
      const response = await authenticatedFetch(`${OAUTH_CONFIG.apiBaseUrl}/userinfo`);
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
        setIsAuthenticated(true);
      } else {
        throw new Error('Failed to fetch user profile');
      }
    } catch (err) {
      console.error('Error fetching user profile:', err);
      setIsAuthenticated(false);
      setUser(null);
    }
  }, []);

  // Handle OAuth callback
  const handleCallback = useCallback(async () => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const errorParam = urlParams.get('error');
    const errorDescription = urlParams.get('error_description');

    if (errorParam) {
      setError(errorDescription || errorParam);
      setIsLoading(false);
      // Clean URL
      window.history.replaceState({}, document.title, '/');
      return;
    }

    if (code && state) {
      try {
        await OAuthService.exchangeCodeForTokens(code, state);
        await fetchUserProfile();
        // Clean URL after successful authentication
        window.history.replaceState({}, document.title, '/');
      } catch (err) {
        console.error('OAuth callback error:', err);
        setError(err.message);
        clearTokens();
      }
      setIsLoading(false);
      return true;
    }
    return false;
  }, [fetchUserProfile]);

  // Initialize auth state
  useEffect(() => {
    async function initAuth() {
      setIsLoading(true);

      // Check if this is a callback
      const isCallback = await handleCallback();
      if (isCallback) return;

      // Check for existing tokens
      const { accessToken } = getStoredTokens();
      if (accessToken && !isTokenExpired()) {
        try {
          await fetchUserProfile();
        } catch (err) {
          console.error('Failed to restore session:', err);
          clearTokens();
        }
      } else if (accessToken && isTokenExpired()) {
        try {
          await OAuthService.refreshAccessToken();
          await fetchUserProfile();
        } catch (err) {
          console.error('Failed to refresh session:', err);
          clearTokens();
        }
      }

      setIsLoading(false);
    }

    initAuth();
  }, [handleCallback, fetchUserProfile]);

  const login = useCallback(() => {
    OAuthService.initiateLogin();
  }, []);

  const logout = useCallback(() => {
    setIsAuthenticated(false);
    setUser(null);
    OAuthService.logout();
  }, []);

  const value = {
    isAuthenticated,
    isLoading,
    user,
    error,
    login,
    logout,
    authenticatedFetch,
  };

  return React.createElement(AuthContext.Provider, { value }, children);
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

